import React, { useEffect, useState } from "react";
import axios from "axios";
import "bootstrap/dist/css/bootstrap.min.css";
import "./App.css";

function App() {

    const [jobs, setJobs] = useState([]);
    const [applications, setApplications] = useState([]);

    const [title, setTitle] = useState("");
    const [description, setDescription] = useState("");
    const [location, setLocation] = useState("");
    const [salary, setSalary] = useState("");

    const [email, setEmail] = useState("");
    const [password, setPassword] = useState("");

    const [registerName, setRegisterName] = useState("");
    const [registerEmail, setRegisterEmail] = useState("");
    const [registerPassword, setRegisterPassword] = useState("");

    const [token, setToken] = useState(localStorage.getItem("token"));
    const [showRegister, setShowRegister] = useState(false);

    useEffect(() => {

        loadJobs();

    }, []);

    const loadJobs = () => {

        axios.get("https://localhost:7059/api/Jobs")
            .then(response => {

                setJobs(response.data);

            })
            .catch(error => {

                console.error(error);

            });
    };

    const login = () => {

        axios.post("https://localhost:7059/api/Auth/login", {
            email,
            password
        })
            .then(response => {

                localStorage.setItem("token", response.data.token);

                setToken(response.data.token);

                alert("Login successful!");

            })
            .catch(error => {

                console.error(error);

                alert("Login failed");

            });
    };

    const register = () => {

        axios.post("https://localhost:7059/api/Auth/register", {
            fullName: registerName,
            email: registerEmail,
            password: registerPassword,
            role: "Candidate"
        })
            .then(response => {

                alert("Registration successful!");

                setShowRegister(false);

            })
            .catch(error => {

                console.error(error);

                alert("Registration failed");

            });
    };

    const createJob = () => {

        axios.post(
            "https://localhost:7059/api/Jobs",
            {
                title,
                description,
                location,
                salary
            },
            {
                headers: {
                    Authorization: `Bearer ${token}`
                }
            }
        )
            .then(response => {

                loadJobs();

                setTitle("");
                setDescription("");
                setLocation("");
                setSalary("");

                alert("Job added!");

            })
            .catch(error => {

                console.error(error);

                alert("Could not add job");

            });
    };

    const applyJob = (jobId) => {

        axios.post(
            "https://localhost:7059/api/Applications",
            {
                jobId
            },
            {
                headers: {
                    Authorization: `Bearer ${token}`
                }
            }
        )
            .then(response => {

                alert("Application sent!");

            })
            .catch(error => {

                console.error(error);

                alert("Could not apply");

            });
    };

    const loadApplications = () => {

        axios.get("https://localhost:7059/api/Applications")
            .then(response => {

                setApplications(response.data);

            })
            .catch(error => {

                console.error(error);

                alert("Could not load applications");

            });
    };

    const logout = () => {

        localStorage.removeItem("token");

        setToken(null);
    };

    if (!token) {

        return (

            <div className="container mt-5">

                <div className="hero-section">

                    <h1 className="hero-title">
                        Recruitment Platform
                    </h1>

                    <p className="hero-text mt-3">
                        Find your dream job or recruit top developers.
                    </p>

                </div>

                <div
                    className="card shadow p-4 mx-auto"
                    style={{ maxWidth: "500px" }}
                >

                    {!showRegister ? (

                        <>

                            <h3 className="mb-4">
                                Login
                            </h3>

                            <input
                                type="email"
                                className="form-control mb-3"
                                placeholder="Email"
                                value={email}
                                onChange={(e) => setEmail(e.target.value)}
                            />

                            <input
                                type="password"
                                className="form-control mb-3"
                                placeholder="Password"
                                value={password}
                                onChange={(e) => setPassword(e.target.value)}
                            />

                            <button
                                className="btn btn-primary w-100"
                                onClick={login}
                            >
                                Login
                            </button>

                            <button
                                className="btn btn-outline-secondary w-100 mt-3"
                                onClick={() => setShowRegister(true)}
                            >
                                Create Account
                            </button>

                        </>

                    ) : (

                        <>

                            <h3 className="mb-4">
                                Register
                            </h3>

                            <input
                                type="text"
                                className="form-control mb-3"
                                placeholder="Full Name"
                                value={registerName}
                                onChange={(e) => setRegisterName(e.target.value)}
                            />

                            <input
                                type="email"
                                className="form-control mb-3"
                                placeholder="Email"
                                value={registerEmail}
                                onChange={(e) => setRegisterEmail(e.target.value)}
                            />

                            <input
                                type="password"
                                className="form-control mb-3"
                                placeholder="Password"
                                value={registerPassword}
                                onChange={(e) => setRegisterPassword(e.target.value)}
                            />

                            <button
                                className="btn btn-success w-100"
                                onClick={register}
                            >
                                Register
                            </button>

                            <button
                                className="btn btn-outline-secondary w-100 mt-3"
                                onClick={() => setShowRegister(false)}
                            >
                                Back To Login
                            </button>

                        </>

                    )}

                </div>

            </div>

        );
    }

    return (

        <>

            <nav className="navbar navbar-dark bg-dark px-4">

                <span className="navbar-brand">
                    Recruitment Platform
                </span>

                <div>

                    <button
                        className="btn btn-outline-light me-3"
                        onClick={loadApplications}
                    >
                        View Applications
                    </button>

                    <button
                        className="btn btn-danger"
                        onClick={logout}
                    >
                        Logout
                    </button>

                </div>

            </nav>

            <div className="container mt-5">

                <div className="hero-section">

                    <h1 className="hero-title">
                        Recruitment Platform
                    </h1>

                    <p className="hero-text mt-3">
                        Find your dream job or recruit the best developers in Sweden.
                    </p>

                </div>

                <div className="row mb-5">

                    <div className="col-md-4">

                        <div className="stats-box">

                            <div className="stats-number">
                                {jobs.length}
                            </div>

                            <div>
                                Active Jobs
                            </div>

                        </div>

                    </div>

                    <div className="col-md-4">

                        <div className="stats-box">

                            <div className="stats-number">
                                120+
                            </div>

                            <div>
                                Companies
                            </div>

                        </div>

                    </div>

                    <div className="col-md-4">

                        <div className="stats-box">

                            <div className="stats-number">
                                500+
                            </div>

                            <div>
                                Applications
                            </div>

                        </div>

                    </div>

                </div>

                <div className="card shadow-sm p-4 mb-5">

                    <h2 className="mb-4">
                        Create New Job
                    </h2>

                    <div className="row">

                        <div className="col-md-3">

                            <input
                                className="form-control"
                                placeholder="Title"
                                value={title}
                                onChange={(e) => setTitle(e.target.value)}
                            />

                        </div>

                        <div className="col-md-3">

                            <input
                                className="form-control"
                                placeholder="Description"
                                value={description}
                                onChange={(e) => setDescription(e.target.value)}
                            />

                        </div>

                        <div className="col-md-2">

                            <input
                                className="form-control"
                                placeholder="Location"
                                value={location}
                                onChange={(e) => setLocation(e.target.value)}
                            />

                        </div>

                        <div className="col-md-2">

                            <input
                                className="form-control"
                                placeholder="Salary"
                                value={salary}
                                onChange={(e) => setSalary(e.target.value)}
                            />

                        </div>

                        <div className="col-md-2">

                            <button
                                className="btn btn-primary w-100"
                                onClick={createJob}
                            >
                                Add Job
                            </button>

                        </div>

                    </div>

                </div>

                <div className="row">

                    {jobs.map(job => (

                        <div
                            className="col-md-4 mb-4"
                            key={job.id}
                        >

                            <div className="card shadow-sm job-card h-100">

                                <div className="card-body d-flex flex-column">

                                    <h3 className="card-title mb-3">
                                        {job.title}
                                    </h3>

                                    <p className="card-text">
                                        {job.description}
                                    </p>

                                    <p>
                                        <strong>Location:</strong> {job.location}
                                    </p>

                                    <p>
                                        <strong>Salary:</strong> {job.salary} SEK
                                    </p>

                                    <button
                                        className="btn btn-success mt-auto"
                                        onClick={() => applyJob(job.id)}
                                    >
                                        Apply
                                    </button>

                                </div>

                            </div>

                        </div>

                    ))}

                </div>

                {applications.length > 0 && (

                    <div className="mt-5">

                        <h2 className="mb-4">
                            Applications
                        </h2>

                        <div className="table-responsive">

                            <table className="table table-bordered bg-white">

                                <thead className="table-dark">

                                    <tr>
                                        <th>Job</th>
                                        <th>Candidate</th>
                                        <th>Email</th>
                                    </tr>

                                </thead>

                                <tbody>

                                    {applications.map(app => (

                                        <tr key={app.id}>

                                            <td>
                                                {app.job?.title}
                                            </td>

                                            <td>
                                                {app.candidate?.fullName}
                                            </td>

                                            <td>
                                                {app.candidate?.email}
                                            </td>

                                        </tr>

                                    ))}

                                </tbody>

                            </table>

                        </div>

                    </div>

                )}

            </div>

            <div className="footer">

                <h5>
                    Recruitment Platform
                </h5>

                <p className="mb-0">
                    Built with React + ASP.NET Core + SQL Server
                </p>

            </div>

        </>

    );
}

export default App;
